const input = $input.first().json.body ?? $input.first().json;
const lead = {
  lead_id: input.lead_id ?? `lead_${Date.now()}`,
  source: input.source,
  received_at: input.received_at ?? new Date().toISOString(),
  contact: {
    name: input.name ?? null,
    email: input.email ?? null,
    phone: input.phone ?? null,
    company: input.company ?? null
  },
  content: {
    message: input.message ?? null,
    transcript: input.transcript ?? null
  },
  metadata: {
    campaign: input.campaign ?? null,
    language: input.language ?? 'en',
    external_id: input.external_id ?? null
  },
  raw_input: input
};
return [{ json: { lead, raw_input: input } }];

const data = $input.first().json;
const lead = data.lead;
const errors = [];
if (!['website_form', 'facebook_ad', 'missed_call_transcript'].includes(lead.source)) errors.push('UNSUPPORTED_SOURCE');
if (!lead.contact.email && !lead.contact.phone) errors.push('MISSING_CONTACT_METHOD');
if (!lead.content.message && !lead.content.transcript) errors.push('MISSING_MESSAGE_CONTENT');
if (errors.length > 0) {
  const code = errors[0];
  const error = {
    code,
    message: 'Lead input failed validation.',
    details: { errors }
  };
  const error_log = {
    error_id: `err_${Date.now()}`,
    lead_id: lead.lead_id ?? null,
    timestamp: new Date().toISOString(),
    workflow_name: 'AI LeadOps Main',
    node_name: 'Validate Lead',
    error_code: code,
    error_message: error.message,
    status: 'FAILED',
    raw_input: data.raw_input,
    raw_ai_output: null
  };
  return [{ json: { ...data, status: 'error', error, error_log, response: { status: 'error', error } } }];
}
return [{ json: { ...data, status: 'success' } }];

const leadData = $('Validate Lead').all()[0].json;
const response = $input.first().json;
function buildError(code, message, details, rawAiOutput) {
  const lead = leadData.lead;
  const error = { code, message, details };
  const error_log = {
    error_id: `err_${Date.now()}`,
    lead_id: lead.lead_id ?? null,
    timestamp: new Date().toISOString(),
    workflow_name: 'AI LeadOps Main',
    node_name: 'Validate AI Output',
    error_code: code,
    error_message: message,
    status: 'FAILED',
    raw_input: leadData.raw_input,
    raw_ai_output: rawAiOutput ?? null
  };
  return [{ json: { ...leadData, status: 'error', error, error_log, response: { status: 'error', error } } }];
}
if (response.error || response.statusCode >= 400) {
  return buildError('AI_GATEWAY_FAILED', 'AI Gateway request failed.', { gateway_response: response }, response);
}
const output = response.output;
const required = ['lead_summary', 'lead_type', 'intent', 'priority', 'lead_score', 'recommended_next_step', 'suggested_email_reply', 'suggested_sms_reply', 'crm_fields'];
if (!output || typeof output !== 'object') {
  return buildError('AI_SCHEMA_VALIDATION_FAILED', 'AI Gateway returned invalid output.', { missing: ['output'] }, response);
}
const missing = required.filter((field) => output[field] === undefined || output[field] === null);
if (missing.length > 0 || !Number.isInteger(output.lead_score) || output.lead_score < 0 || output.lead_score > 100) {
  return buildError('AI_SCHEMA_VALIDATION_FAILED', 'AI output failed schema validation.', { missing }, output);
}
return [{ json: { ...leadData, status: 'success', ai_gateway_response: response } }];

const data = $input.first().json;
const lead = data.lead;
const response = data.ai_gateway_response;
const output = response.output;
const statusByFollowUp = {
  'Draft Created': 'DRAFT_CREATED',
  'Needs Review': 'NEEDS_REVIEW',
  'No Action': 'NO_ACTION'
};
const shouldAttachBookingLink = output.intent === 'Book Consultation';
const booking_link = shouldAttachBookingLink && $env.BOOKING_LINK ? $env.BOOKING_LINK : null;
const email_draft = booking_link ? `${output.suggested_email_reply}\n\nBooking link: ${booking_link}` : output.suggested_email_reply;
const crm = {
  lead_id: lead.lead_id,
  received_at: lead.received_at,
  source: lead.source,
  name: lead.contact.name,
  email: lead.contact.email,
  phone: lead.contact.phone,
  company: lead.contact.company,
  lead_type: output.lead_type,
  intent: output.intent,
  priority: output.priority,
  lead_score: output.lead_score,
  service_requested: output.service_requested,
  pain_point: output.pain_point,
  lead_summary: output.lead_summary,
  recommended_next_step: output.recommended_next_step,
  pipeline_stage: output.crm_fields.pipeline_stage,
  follow_up_status: output.crm_fields.follow_up_status,
  email_draft,
  sms_draft: output.suggested_sms_reply,
  booking_link,
  status: statusByFollowUp[output.crm_fields.follow_up_status] ?? 'NEEDS_REVIEW',
  error_code: null
};
const slack_alert = crm.lead_score >= 75 ? {
  channel: $env.SLACK_CHANNEL_ID || '#sales',
  text: `High-priority lead: ${crm.name ?? crm.phone ?? crm.email}`,
  fields: {
    lead_id: crm.lead_id,
    company: crm.company,
    source: crm.source,
    priority: crm.priority,
    lead_score: crm.lead_score,
    intent: crm.intent,
    recommended_next_step: crm.recommended_next_step
  }
} : null;
const gmail_draft = crm.email ? {
  to: crm.email,
  subject: `Re: ${crm.service_requested ?? 'Your inquiry'}`,
  body: crm.email_draft
} : null;
return [{ json: { ...data, crm_record: crm, slack_alert, gmail_draft, booking_link } }];

const data = $('Build CRM Record').all()[0].json;
const crm = data.crm_record;
function readNodeOutput(name) {
  try {
    return $(name).all()[0]?.json ?? null;
  } catch {
    return null;
  }
}
const sink_warnings = [];
const slack_output = readNodeOutput('Send Slack Alert');
if (data.slack_alert && slack_output?.error) {
  sink_warnings.push({
    code: 'SLACK_NOTIFY_FAILED',
    message: 'Slack notification failed.',
    details: slack_output.error
  });
}
const gmail_output = readNodeOutput('Create Gmail Draft');
if (data.gmail_draft && gmail_output?.error) {
  sink_warnings.push({
    code: 'GMAIL_DRAFT_FAILED',
    message: 'Gmail draft creation failed.',
    details: gmail_output.error
  });
}
const sms_draft = crm.phone ? {
  phone: crm.phone,
  body: crm.sms_draft,
  status: 'draft_created'
} : null;
return [{ json: { ...data, sms_draft, sink_warnings } }];

const data = $input.first().json;
const crm = data.crm_record;
const warnings = data.sink_warnings ?? [];
const warningCodes = new Set(warnings.map((warning) => warning.code));
const slack_alert_sent = Boolean(data.slack_alert) && !warningCodes.has('SLACK_NOTIFY_FAILED');
const gmail_draft_created = Boolean(data.gmail_draft) && !warningCodes.has('GMAIL_DRAFT_FAILED');
const sms_draft_created = Boolean(data.sms_draft);
const booking_link = crm.booking_link ?? null;
const success_log = {
  timestamp: new Date().toISOString(),
  lead_id: crm.lead_id,
  workflow_name: 'AI LeadOps Main',
  status: warnings.length > 0 ? 'SUCCESS_WITH_WARNINGS' : 'SUCCESS',
  provider: data.ai_gateway_response.provider,
  model: data.ai_gateway_response.model,
  priority: crm.priority,
  lead_score: crm.lead_score,
  crm_record_created: true,
  slack_alert_sent,
  gmail_draft_created,
  sms_draft_created,
  booking_link_attached: Boolean(booking_link),
  warning_count: warnings.length,
  warnings
};
return [{
  json: {
    ...data,
    crm_record: crm,
    gmail_draft: data.gmail_draft,
    booking_link,
    success_log,
    response: {
      status: warnings.length > 0 ? 'success_with_warnings' : 'success',
      lead_id: crm.lead_id,
      priority: crm.priority,
      lead_score: crm.lead_score,
      crm_record_created: true,
      slack_alert_sent,
      gmail_draft_created,
      sms_draft_created,
      booking_link_attached: Boolean(booking_link),
      warnings,
      next_step: 'Review the generated drafts and contact the lead.'
    }
  }
}];
